external_knowledge:
- "Issues" refers to the alerts in the database;
- "Closed" here means the alerts with a 'Resolved' status;
- The "security service provider" could be any entity like Windows, MacOS, or Linux, depending on the type of security service they provide.

sql:
SELECT DISTINCT detection_service
FROM alerts
WHERE provider != 'Windows' AND provider != 'Linux';

SELECT affected_asset
FROM alerts
WHERE LOWER(affected_asset_criticality) = 'critical' AND LOWER(severity) = 'high';

SELECT alerts.*, alert_logs.*
FROM alerts
JOIN alert_logs ON alerts.alert_id = alert_logs.alert_id;

SELECT AVG(alert_confidence) 
FROM alerts 
WHERE severity > (SELECT AVG(severity) FROM alerts);

external_knowledge:
- "serious alerts" refers to 'High' severity alerts;
- "took a while to resolve" means the resolution time is more than 60 minutes;
- "security service provider" is represented by the 'provider' column;
- "site where the issue occurred" refers to the 'affected_asset_location' column.

sql:
SELECT *
FROM alerts
WHERE alert_status = 'In Progress' AND severity = (SELECT MAX(severity) FROM alerts);

SELECT AVG(alert_resolution_time) AS average_resolution_time
FROM alert_logs
WHERE status = 'Resolved';

SELECT COUNT(*)
FROM alert_logs
WHERE status = 'Resolved';

SELECT alert_id, affected_asset, ATAN(alert_id) AS atan_id
FROM alerts
WHERE alert_timestamp > '2023-05-01 10:00:00';

SELECT alert_id, alert_message 
FROM alerts 
ORDER BY severity DESC;

SELECT * 
FROM alerts 
WHERE alert_id NOT IN (
    SELECT alert_id 
    FROM alert_logs
);
